                    <path d="M94.0898 16.2442H95.3963L95.3694 18.5825H95.3855C95.7619 17.1709 96.5898 16.1095 98.3318 16.1095C100.074 16.1095 101.117 17.3164 101.117 19.2775C101.117 21.2387 101.074 20.4251 101.031 20.7161H99.8425C99.8694 20.4682 99.9017 20.0641 99.9017 19.5523C99.9017 18.0545 99.3479 17.284 98.0146 17.284C96.6812 17.284 95.4017 18.7226 95.4017 20.743V24.3367H94.0952V16.2388L94.0898 16.2442Z" fill="#F9F3DC"/>
